module RefModule(
  input clk,
  input reset,
  output [3:0] count,
  output reg overflow  // Change from wire to reg
);reg [3:0] unused_count_reg;

always @(posedge clk) begin
  if (reset) begin
    unused_count_reg <= 4'b0;
    overflow <= 1'b0;
  end else if (unused_count_reg == 4'b1001) begin
    unused_count_reg <= 4'b0;
    overflow <= 1'b1;
  end else begin
    unused_count_reg <= unused_count_reg + 1;
    overflow <= 1'b0;
  end
end

assign count = unused_count_reg;

endmodule
